def es_formula(v):
    return isinstance(v, str) and v.startswith("=")

print(es_formula("=A1"))
print(es_formula(3))

def validate_rows(rows, allowed):
    return [r["region"] for r in rows if r["region"] not in allowed]

print(validate_rows([{"region": "Lima"}, {"region": "Piura"}], {"Lima", "Cusco"}))

from collections import Counter

def batch_status(files_dict):
    return dict(Counter(files_dict.values()))

print(batch_status({"a": "ok", "b": "corrupt"}))

def structural_ok(sheetnames, need):
    return set(sheetnames).issuperset(set(need))

print(structural_ok(["Entrada", "Salida", "X"], ["Entrada", "Salida"]))
